import React from 'react';
import { Routes, Route, useLocation } from 'react-router-dom';
import { AnimatePresence, motion } from 'framer-motion';

// Page Imports
import HomePage from '../pages/HomePage';
import ProductListingPage from '../pages/ProductListing';
import ProductDetailPage from '../pages/ProductDetails';
import CartPage from '../pages/CartPage';
import LoginPage from '../pages/LoginPage';
import RegisterPage from '../pages/RegistrationPage';
import ProfilePage from '../pages/AccountPage';
import AdminDashboard from '../pages/AdminPage';
import CheckoutPage from '../pages/CheckOutpage';
import NotFound from '../pages/NotFound';

// Wrapper for consistent page transitions
const PageTransition = ({ children }) => {
    return (
        <motion.div
            initial={{ opacity: 0, x: -20 }}
            animate={{ opacity: 1, x: 0 }}
            exit={{ opacity: 0, x: 20 }}
            transition={{ duration: 0.3 }}
        >
            {children}
        </motion.div>
    );
};

const AnimatedRoutes = () => {
    const location = useLocation();

    return (
        <AnimatePresence mode="wait">
            <Routes location={location} key={location.pathname}>
                <Route path="/" element={<HomePage />} />
                <Route path="/login" element={<PageTransition><LoginPage /></PageTransition>} />
                <Route path="/register" element={<PageTransition><RegisterPage /></PageTransition>} />
                <Route path="/shop" element={<PageTransition><ProductListingPage /></PageTransition>} />
                <Route path="/product/:id" element={<PageTransition><ProductDetailPage /></PageTransition>} />
                <Route path="/cart" element={<PageTransition><CartPage /></PageTransition>} />
                <Route path="/profile" element={<PageTransition><ProfilePage /></PageTransition>} />
                {/* AdminPage handles its own specific transitions, but we can wrap it too for consistency if desired. 
                    However, keeping it consistent with the global transition is better. */}
                <Route path="/admin" element={<PageTransition><AdminDashboard /></PageTransition>} />
                <Route path="/checkout" element={<PageTransition><CheckoutPage /></PageTransition>} />
                <Route path="*" element={<PageTransition><NotFound /></PageTransition>} />
            </Routes>
        </AnimatePresence>
    );
};

export default AnimatedRoutes;

// src/components/Header.jsx

import React, { useState, useEffect } from 'react';
import { Link, NavLink, useNavigate } from 'react-router-dom';
import { motion, AnimatePresence, useScroll } from 'framer-motion';
import AuthContext from '../context/AuthContext';
import { useToast } from '../context/ToastContext';
import { useCart } from '../context/CartContext';

import candleLogo from '../assets/CANDLE.png';

const Header = () => {
    const [isOpen, setIsOpen] = useState(false);
    const [scrolled, setScrolled] = useState(false);
    const { user, logout } = React.useContext(AuthContext);
    const navigate = useNavigate();
    const { addToast } = useToast();
    const { cartCount, clearCart } = useCart();

    const { scrollY } = useScroll();

    useEffect(() => {
        return scrollY.onChange((latest) => {
            setScrolled(latest > 50);
        });
    }, [scrollY]);

    // Icons
    const MenuIcon = () => <svg xmlns="http://www.w3.org/2000/svg" width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><line x1="3" y1="12" x2="21" y2="12"></line><line x1="3" y1="6" x2="21" y2="6"></line><line x1="3" y1="18" x2="21" y2="18"></line></svg>;
    const XIcon = () => <svg xmlns="http://www.w3.org/2000/svg" width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><line x1="18" y1="6" x2="6" y2="18"></line><line x1="6" y1="6" x2="18" y2="18"></line></svg>;
    const ShoppingCartIcon = () => <svg xmlns="http://www.w3.org/2000/svg" width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><circle cx="9" cy="21" r="1"></circle><circle cx="20" cy="21" r="1"></circle><path d="M1 1h4l2.68 13.39a2 2 0 0 0 2 1.61h9.72a2 2 0 0 0 2-1.61L23 6H6"></path></svg>;
    const UserIcon = () => <svg xmlns="http://www.w3.org/2000/svg" width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="M20 21v-2a4 4 0 0 0-4-4H8a4 4 0 0 0-4 4v2"></path><circle cx="12" cy="7" r="4"></circle></svg>;
    const LogOutIcon = () => <svg xmlns="http://www.w3.org/2000/svg" width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="M9 21H5a2 2 0 0 1-2-2V5a2 2 0 0 1 2-2h4"></path><polyline points="16 17 21 12 16 7"></polyline><line x1="21" y1="12" x2="9" y2="12"></line></svg>;

    const handleLogout = () => {
        logout();
        clearCart();
        addToast('Logged out successfully', 'info');
        navigate('/');
    };

    const navLinks = [
        { path: '/', label: 'Home' },
        { path: '/shop', label: 'Shop' },
        { path: '/admin', label: 'Admin', admin: true },
    ];

    // Dynamic Text Classes based on Scroll State
    const textColorClass = scrolled ? 'text-charcoal' : 'text-white';
    const hoverColorClass = scrolled ? 'hover:text-flame' : 'hover:text-primary';

    return (
        <motion.header
            className={`fixed top-0 left-0 w-full z-50 transition-all duration-500 ease-in-out px-4 sm:px-8 
                ${scrolled ? 'bg-white/90 backdrop-blur-xl shadow-sm border-b border-shadow/20 py-4' : 'bg-gradient-to-b from-black/60 to-transparent py-6'}`}
        >
            <div className="container mx-auto flex justify-between items-center">

                {/* 1. Logo */}
                <Link to="/" className="group z-50 flex items-center gap-3">
                    {/* Logo: Invert brightness when not scrolled (to make it white), standard when scrolled (dark) */}
                    <img
                        src={candleLogo}
                        alt="CandlesWithKinzee"
                        className={`h-9 w-9 rounded-full object-cover transition-all duration-300 ${!scrolled ? 'brightness-0 invert' : ''}`}
                    />
                    <span className={`text-xl md:text-2xl font-serif font-bold tracking-tight transition-colors duration-300 ${scrolled ? 'text-brown' : 'text-white'}`}>
                        CandlesWith<span className="font-light">Kinzee</span>
                    </span>
                </Link>

                {/* 2. Desktop Navigation (Centered) */}
                <nav className="hidden md:flex items-center space-x-8 absolute left-1/2 transform -translate-x-1/2">
                    {navLinks.map((link) => {
                        if (link.auth && !user) return null;
                        // Hide Profile link for Admin
                        if (link.path === '/profile' && user?.isAdmin) return null;
                        if (link.admin && (!user || !user.isAdmin)) return null;
                        // Actually, I'll allow it for mobile menu visibility logic or just rely on the UserIcon for desktop.
                        // The loop maps navLinks. Let's check navLinks definition.


                        return (
                            <NavLink
                                key={link.path}
                                to={link.path}
                                className={({ isActive }) =>
                                    `text-sm font-medium tracking-wide uppercase transition-all duration-200 relative group ${isActive ? 'font-bold' : ''} ${textColorClass} ${hoverColorClass}`
                                }
                            >
                                {({ isActive }) => (
                                    <>
                                        {link.label}
                                        <span className={`absolute -bottom-1 left-0 w-0 h-0.5 transition-all duration-300 group-hover:w-full ${scrolled ? 'bg-flame' : 'bg-white'}`}></span>
                                    </>
                                )}
                            </NavLink>
                        );
                    })}
                </nav>

                <div className={`hidden md:flex items-center space-x-6 z-50 ${textColorClass}`}>

                    {/* Cart - Hide for Admin and Guests */}
                    {user && !user.isAdmin && (
                        <Link to="/cart" className={`relative p-1 transition-colors ${hoverColorClass}`} title="Cart">
                            <ShoppingCartIcon />
                            {cartCount > 0 && (
                                <span className="absolute -top-1 -right-1 flex h-4 w-4 items-center justify-center rounded-full bg-flame text-[10px] text-white font-bold">
                                    {cartCount}
                                </span>
                            )}
                        </Link>
                    )}

                    {/* User Section */}
                    {user ? (
                        <div className="flex items-center space-x-4">

                            {/* Profile Link: Show for everyone, but we use the enhanced UI from main */}
                            <Link
                                to="/profile"
                                className={`flex items-center gap-3 transition-colors group ${hoverColorClass}`}
                                title="My Profile"
                            >
                                <span className="font-medium text-sm hidden sm:block">Profile</span>
                                {user.profileImage ? (
                                    <img
                                        src={user.profileImage}
                                        alt={user.name}
                                        className="w-10 h-10 rounded-full object-cover border-2 border-white/50 shadow-sm"
                                    />
                                ) : (
                                    <div className="w-10 h-10 rounded-full bg-gray-200 flex items-center justify-center text-lg shadow-sm">
                                        👤
                                    </div>
                                )}
                            </Link>


                            {/* Separator: Only hide if you specifically want it gone for Admins */}
                            <div className={`h-4 w-px ${scrolled ? 'bg-charcoal/20' : 'bg-white/30'}`}></div>

                            {/* Logout Button */}
                            <button
                                onClick={handleLogout}
                                className={`flex items-center gap-2 transition-colors ${hoverColorClass}`}
                                title="Logout"
                            >
                                <LogOutIcon />
                            </button>
                        </div>
                    ) : (

                        <Link to="/login">
                            <motion.button
                                whileHover={{ scale: 1.02 }}
                                whileTap={{ scale: 0.98 }}
                                className={`px-5 py-2 rounded-full text-xs font-bold uppercase tracking-widest transition-all duration-300 border 
                                    ${scrolled
                                        ? 'border-charcoal text-charcoal hover:bg-charcoal hover:text-white'
                                        : 'border-white text-white hover:bg-white hover:text-brown'
                                    }`}
                            >
                                Sign In
                            </motion.button>
                        </Link>
                    )}
                </div>

                {/* Mobile Menu Toggle */}
                <div className="md:hidden z-50 flex items-center gap-4">
                    {/* Cloudinary Cart Icon for Mobile */}
                    {user && !user.isAdmin && (
                        <Link to="/cart" className={`relative p-1 transition-colors ${textColorClass}`} title="Cart">
                            <ShoppingCartIcon />
                            {cartCount > 0 && (
                                <span className="absolute -top-1 -right-1 flex h-4 w-4 items-center justify-center rounded-full bg-flame text-[10px] text-white font-bold">
                                    {cartCount}
                                </span>
                            )}
                        </Link>
                    )}
                    <button onClick={() => setIsOpen(!isOpen)} className={`${textColorClass}`}>
                        {isOpen ? <XIcon /> : <MenuIcon />}
                    </button>
                </div>
            </div>

            {/* Mobile Menu Overlay */}
            <AnimatePresence>
                {isOpen && (
                    <motion.div
                        initial={{ opacity: 0, y: -20 }}
                        animate={{ opacity: 1, y: 0 }}
                        exit={{ opacity: 0, y: -20 }}
                        className="absolute top-full left-0 w-full bg-white shadow-xl border-t border-neutral-100 py-6 px-6 flex flex-col space-y-4 md:hidden"
                    >
                        {navLinks.map((link) => {
                            if (link.auth && !user) return null;
                            if (link.admin && (!user || !user.isAdmin)) return null;
                            return (
                                <Link
                                    key={link.path}
                                    to={link.path}
                                    className="text-lg font-serif text-charcoal"
                                    onClick={() => setIsOpen(false)}
                                >
                                    {link.label}
                                </Link>
                            );
                        })}
                        <hr className="border-neutral-100" />
                        {user ? (
                            <button onClick={() => { handleLogout(); setIsOpen(false); }} className="text-left text-primary font-medium">Logout</button>
                        ) : (
                            <Link to="/login" onClick={() => setIsOpen(false)} className="text-primary font-medium">Sign In</Link>
                        )}
                    </motion.div>
                )}
            </AnimatePresence>

        </motion.header>
    );
};

export default Header;

import React from 'react';
import { motion } from 'framer-motion';

export default function HeroSection() {
    return (
        <div className="relative bg-beige h-96 md:h-[550px] flex items-center justify-center overflow-hidden">
            {/* Background Glow Effect */}
            <motion.div
                initial={{ scale: 0.9, opacity: 0.5 }}
                animate={{ scale: 1.05, opacity: 0.8 }}
                transition={{ duration: 6, repeat: Infinity, repeatType: "reverse", ease: "easeInOut" }}
                className="absolute inset-0 bg-primary/40 blur-3xl opacity-50 pointer-events-none"
            />

            <div className="relative z-10 text-center p-6 max-w-4xl">
                <motion.h2
                    initial={{ y: 20, opacity: 0 }}
                    animate={{ y: 0, opacity: 1 }}
                    transition={{ duration: 0.6, delay: 0.2 }}
                    className="text-5xl md:text-8xl font-black text-brown tracking-tighter mb-4 leading-tight"
                >
                    Handcrafted Comfort.
                </motion.h2>
                <motion.p
                    initial={{ y: 20, opacity: 0 }}
                    animate={{ y: 0, opacity: 1 }}
                    transition={{ duration: 0.6, delay: 0.4 }}
                    className="text-xl md:text-3xl text-charcoal/80 mb-10 font-light italic"
                >
                    Experience the pure glow of artisanal candles, ethically made for your home.
                </motion.p>
                <motion.button
                    initial={{ scale: 0.8, opacity: 0, boxShadow: "0 25px 50px -12px rgba(0, 0, 0, 0.25)" }}
                    animate={{ scale: 1, opacity: 1 }}
                    transition={{ type: "spring", stiffness: 200, damping: 10, delay: 0.6 }}
                    className="bg-flame text-charcoal font-bold py-3 px-10 rounded-full text-lg"
                    whileHover={{
                        scale: 1.08,
                        boxShadow: "0 8px 20px rgba(255, 159, 28, 0.6)",
                        backgroundColor: "#F5C76B"
                    }}
                    whileTap={{ scale: 0.95 }}
                >
                    Explore Scents
                </motion.button>
            </div>
        </div>
    );
}

// src/components/ProductCard.jsx

import React from 'react';
import { motion } from 'framer-motion';
import { getValidImageUrl } from '../utils/imageHelper';

// --- Image Mapping Function ---
const generatePlaceholderUrl = (name) => {
    const slug = name.toLowerCase().replace(/ /g, '-').replace(/[^\w-]+/g, '');
    return `https://res.cloudinary.com/demo/image/fetch/w_500,h_600,c_fill,g_auto/f_auto/${slug}.jpg`;
};

export default function ProductCard({ product }) {
    // Use robust helper for image URL
    let imageUrl = getValidImageUrl(product?.image);
    imageUrl = imageUrl || generatePlaceholderUrl(product?.name || 'Default Candle');

    return (
        <motion.div
            className="group relative cursor-pointer flex flex-col items-center"
            initial="idle"
            whileHover="hover"
            whileTap={{ scale: 0.98 }}
        >
            {/* Image Container */}
            <div className="relative w-full aspect-[4/5] overflow-hidden bg-beige mb-6 rounded-none">
                <motion.img
                    src={imageUrl}
                    alt={product?.name}
                    className="w-full h-full object-cover"
                    onError={(e) => { e.target.onerror = null; e.target.src = generatePlaceholderUrl(product?.name || 'Candle'); }}
                    variants={{
                        idle: { scale: 1 },
                        hover: { scale: 1.08 }
                    }}
                    transition={{ duration: 0.8, ease: "easeOut" }}
                />

                {/* Add to Cart Overlay */}
                <motion.div
                    className="absolute inset-x-0 bottom-0 p-6 flex justify-center items-end bg-gradient-to-t from-charcoal/40 to-transparent"
                    variants={{
                        idle: { opacity: 0, y: 10 },
                        hover: { opacity: 1, y: 0 }
                    }}
                    transition={{ duration: 0.4, ease: "easeOut" }}
                >
                    <button
                        className="w-full bg-white/90 backdrop-blur-sm text-charcoal font-medium py-3 px-6 shadow-xl uppercase tracking-widest text-xs hover:bg-black hover:text-white transition-all duration-300 pointer-events-auto"
                        onClick={(e) => {
                            e.preventDefault();
                            e.stopPropagation();
                            // Logic to add to cart would go here
                            console.log('Add to cart clicked');
                        }}
                    >
                        Add to Cart
                    </button>
                </motion.div>
            </div>

            {/* Product Details */}
            <div className="text-center px-4 w-full">
                <h3 className="text-lg md:text-xl font-serif text-charcoal mb-2 line-clamp-1 group-hover:text-primary transition-colors duration-300">
                    {product?.name}
                </h3>
                <p className="text-sm font-light tracking-wide text-brown">
                    ${product?.price ? product.price.toFixed(2) : '0.00'}
                </p>
            </div>
        </motion.div>
    );
}

import React, { createContext, useContext, useState, useEffect } from 'react';
import { useToast } from './ToastContext';

const CartContext = createContext();

export const CartProvider = ({ children }) => {
    const [cartItems, setCartItems] = useState(() => {
        const storedCart = localStorage.getItem('cart');
        return storedCart ? JSON.parse(storedCart) : [];
    });

    const { addToast } = useToast();

    useEffect(() => {
        localStorage.setItem('cart', JSON.stringify(cartItems));
    }, [cartItems]);

    const addToCart = (product, quantity = 1) => {
        setCartItems(prevItems => {
            const existingItem = prevItems.find(item => item._id === product._id);

            // Check if adding this quantity exceeds total stock
            const currentQty = existingItem ? existingItem.quantity : 0;
            if (currentQty + quantity > product.countInStock) {
                addToast(`Sorry, only ${product.countInStock} items in stock`, 'error');
                return prevItems; // Return unchanged
            }

            if (existingItem) {
                addToast(`${product.name} quantity updated in cart`, 'success');
                return prevItems.map(item =>
                    item._id === product._id
                        ? { ...item, quantity: item.quantity + quantity }
                        : item
                );
            }

            addToast(`${product.name} added to cart`, 'success');
            // Ensure we store the latest countInStock with the item
            return [...prevItems, { ...product, quantity }];
        });
    };

    const removeFromCart = (id) => {
        setCartItems(prevItems => prevItems.filter(item => item._id !== id));
        addToast('Item removed from cart', 'info');
    };

    const updateQuantity = (id, quantity) => {
        if (quantity < 1) return;

        setCartItems(prevItems => {
            return prevItems.map(item => {
                if (item._id === id) {
                    // Check stock limit
                    if (quantity > item.countInStock) {
                        addToast(`Cannot add more. Only ${item.countInStock} in stock.`, 'error');
                        return item; // Return unchanged
                    }
                    return { ...item, quantity: quantity };
                }
                return item;
            });
        });
    };

    const clearCart = () => {
        setCartItems([]);
    };

    const cartCount = cartItems.reduce((acc, item) => acc + item.quantity, 0);
    const cartTotal = cartItems.reduce((acc, item) => acc + item.price * item.quantity, 0);

    return (
        <CartContext.Provider value={{ cartItems, addToCart, removeFromCart, updateQuantity, clearCart, cartCount, cartTotal }}>
            {children}
        </CartContext.Provider>
    );
};

export const useCart = () => {
    return useContext(CartContext);
};

import React, { createContext, useContext, useState, useCallback } from 'react';
import Toast from '../components/Toast';

const ToastContext = createContext();

export const useToast = () => useContext(ToastContext);

export const ToastProvider = ({ children }) => {
    const [toasts, setToasts] = useState([]);

    const addToast = useCallback((message, type = 'success') => {
        const id = Date.now();
        setToasts(prev => [...prev, { id, message, type }]);
    }, []);

    const removeToast = useCallback((id) => {
        setToasts(prev => prev.filter(t => t.id !== id));
    }, []);

    return (
        <ToastContext.Provider value={{ addToast }}>
            {children}
            <div className="fixed bottom-0 right-0 p-4 z-50 pointer-events-none flex flex-col items-end space-y-2">
                {toasts.map(toast => (
                    <div key={toast.id} className="pointer-events-auto">
                        <Toast
                            message={toast.message}
                            type={toast.type}
                            onClose={() => removeToast(toast.id)}
                        />
                    </div>
                ))}
            </div>
        </ToastContext.Provider>
    );
};

import React, { useState, useEffect, useContext } from 'react';
import { motion } from 'framer-motion';
import SEO from '../components/SEO.jsx';
import AuthContext from '../context/AuthContext';
import { useToast } from '../context/ToastContext';
import API_BASE_URL from '../config/api';

// Placeholder icons (using emojis for simplicity and aesthetic fit)
const ProfileIcon = () => '👤';
const OrdersIcon = () => '📦';
const AddressIcon = () => '🏠';
const SettingsIcon = () => '⚙️';

const ProfilePage = () => {
    const { user, updateUser } = React.useContext(AuthContext); // Access AuthContext
    const { addToast } = useToast();
    const [activeSection, setActiveSection] = useState('profile');
    const [profile, setProfile] = useState(null);
    const [orders, setOrders] = useState([]);
    const [loading, setLoading] = useState(true);

    // Editing States
    const [editingProfile, setEditingProfile] = useState(false);
    const [addingAddress, setAddingAddress] = useState(false);
    const [addingCard, setAddingCard] = useState(false);

    // Form Data
    const [profileForm, setProfileForm] = useState({ name: '', email: '', phoneNumber: '', password: '', profileImage: '' });
    const [addressForm, setAddressForm] = useState({ street: '', city: '', postalCode: '', country: '' });
    const [cardForm, setCardForm] = useState({ number: '', expiry: '', holderName: '', cvc: '' });

    // Framer Motion variant
    const pageVariants = {
        initial: { opacity: 0, y: 10 },
        animate: { opacity: 1, y: 0, transition: { duration: 0.5, ease: "easeOut" } }
    };

    useEffect(() => {
        if (user) {
            fetchProfile();
            fetchOrders();
        }
    }, [user]);

    const fetchProfile = async () => {
        try {
            const res = await fetch(`${API_BASE_URL}/api/auth/profile`, {
                headers: { Authorization: `Bearer ${user.token}` }
            });
            if (!res.ok) throw new Error(`API: ${res.status}`);
            const ct = res.headers.get("content-type");
            if (!ct || !ct.includes("application/json")) throw new TypeError("Non-JSON API response");
            const data = await res.json();
            setProfile(data);
            setProfileForm({ name: data.name, email: data.email, phoneNumber: data.phoneNumber || '', password: '', profileImage: data.profileImage || '' });
        } catch (error) { console.error(error); } finally { setLoading(false); }
    };

    const fetchOrders = async () => {
        try {
            const res = await fetch(`${API_BASE_URL}/api/orders/myorders`, {
                headers: { Authorization: `Bearer ${user.token}` }
            });
            if (!res.ok) throw new Error(`API: ${res.status}`);
            const ct = res.headers.get("content-type");
            if (!ct || !ct.includes("application/json")) throw new TypeError("Non-JSON API response");
            const data = await res.json();
            setOrders(data);
        } catch (error) { console.error(error); }
    };

    const handleUpdateProfile = async (e) => {
        e.preventDefault();
        try {
            const res = await fetch(`${API_BASE_URL}/api/auth/profile`, {
                method: 'PUT',
                headers: { 'Content-Type': 'application/json', Authorization: `Bearer ${user.token}` },
                body: JSON.stringify(profileForm)
            });
            const data = await res.json();
            if (res.ok) {
                addToast('Profile Updated', 'success');
                setProfile(data); // Immediate update
                updateUser(data); // Update global user state for Header
                setEditingProfile(false);
            } else { addToast(data.message, 'error'); }
        } catch (error) { addToast(error.message, 'error'); }
    };

    const uploadFileHandler = async (e) => {
        const file = e.target.files[0];
        const formData = new FormData();
        formData.append('image', file);

        try {
            const res = await fetch(`${API_BASE_URL}/api/upload`, {
                method: 'POST',
                body: formData,
            });
            const data = await res.json();

            if (res.ok) {
                setProfileForm({ ...profileForm, profileImage: data.url });
                addToast('Image Uploaded', 'success');
            } else {
                addToast('Image upload failed', 'error');
            }
        } catch (error) {
            console.error(error);
            addToast('Image upload failed', 'error');
        }
    };

    const handleAddAddress = async (e) => {
        e.preventDefault();
        const newAddresses = [...(profile.addresses || []), addressForm];
        updateUserData({ addresses: newAddresses }, () => {
            setAddingAddress(false);
            setAddressForm({ street: '', city: '', postalCode: '', country: '' });
            addToast('Address Added', 'success');
        });
    };

    const handleRemoveAddress = (index) => {
        const newAddresses = profile.addresses.filter((_, i) => i !== index);
        updateUserData({ addresses: newAddresses }, () => addToast('Address Removed', 'info'));
    };

    const handleAddCard = async (e) => {
        e.preventDefault();
        // Simulation: "Encrypt" and mask data
        const last4 = cardForm.number.slice(-4);
        const cardType = getCardType(cardForm.number);
        const encryptedData = btoa(JSON.stringify(cardForm)); // Mock encryption

        const newMethod = {
            cardType,
            last4,
            expiryDate: cardForm.expiry,
            holderName: cardForm.holderName,
            encryptedData
        };

        const newMethods = [...(profile.paymentMethods || []), newMethod];
        updateUserData({ paymentMethods: newMethods }, () => {
            setAddingCard(false);
            setCardForm({ number: '', expiry: '', holderName: '', cvc: '' });
            addToast('Card Saved Securely', 'success');
        });
    };

    const handleRemoveCard = (index) => {
        const newMethods = profile.paymentMethods.filter((_, i) => i !== index);
        updateUserData({ paymentMethods: newMethods }, () => addToast('Card Removed', 'info'));
    };

    // Helper to update specific fields via PUT
    const updateUserData = async (updates, onSuccess) => {
        try {
            const res = await fetch(`${API_BASE_URL}/api/auth/profile`, {
                method: 'PUT',
                headers: { 'Content-Type': 'application/json', Authorization: `Bearer ${user.token}` },
                body: JSON.stringify(updates)
            });
            const data = await res.json();
            if (res.ok) {
                setProfile(data);
                updateUser(data); // Sync global user state
                if (onSuccess) onSuccess();
            } else { addToast(data.message, 'error'); }
        } catch (e) { addToast(e.message, 'error'); }
    };

    // Utility
    const getCardType = (number) => {
        if (/^4/.test(number)) return 'Visa';
        if (/^5/.test(number)) return 'MasterCard';
        return 'Card';
    };

    // --- Render Helpers (Functions, not Components, to prevent remounting/focus loss) ---

    if (loading || !profile) return <div className="p-10 text-center">Loading Profile...</div>;

    const renderProfileDetails = () => (
        <div className="space-y-6">
            <h2 className="text-2xl font-bold text-charcoal">Personal Information</h2>
            {editingProfile ? (
                <form onSubmit={handleUpdateProfile} className="bg-beige p-6 rounded-lg space-y-4">
                    <div className="flex justify-center mb-6">
                        <div className="relative">
                            <div className="w-32 h-32 rounded-full overflow-hidden border-4 border-white shadow-lg bg-gray-200 flex items-center justify-center">
                                {profileForm.profileImage ? (
                                    <img src={profileForm.profileImage} alt="Profile" className="w-full h-full object-cover" />
                                ) : (
                                    <span className="text-4xl">👤</span>
                                )}
                            </div>
                            <label className="absolute bottom-0 right-0 bg-flame text-white hover:bg-brown p-2 rounded-full cursor-pointer shadow-md transition-colors">
                                <svg xmlns="http://www.w3.org/2000/svg" width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="M23 19a2 2 0 0 1-2 2H3a2 2 0 0 1-2-2V8a2 2 0 0 1 2-2h4l2-3h6l2 3h4a2 2 0 0 1 2 2z"></path><circle cx="12" cy="13" r="4"></circle></svg>
                                <input type='file' onChange={uploadFileHandler} className="hidden" />
                            </label>
                        </div>
                    </div>

                    <div><label className="block text-xs font-bold uppercase text-brown mb-1">Name</label>
                        <input className="w-full p-2 border rounded" value={profileForm.name} onChange={e => setProfileForm({ ...profileForm, name: e.target.value })} /></div>
                    <div><label className="block text-xs font-bold uppercase text-brown mb-1">Email</label>
                        <input className="w-full p-2 border rounded" value={profileForm.email} onChange={e => setProfileForm({ ...profileForm, email: e.target.value })} /></div>
                    <div><label className="block text-xs font-bold uppercase text-brown mb-1">Phone Number</label>
                        <input className="w-full p-2 border rounded" placeholder="+1 (555) 000-0000" value={profileForm.phoneNumber} onChange={e => setProfileForm({ ...profileForm, phoneNumber: e.target.value })} /></div>
                    <div><label className="block text-xs font-bold uppercase text-brown mb-1">New Password (leave blank to keep)</label>
                        <input type="password" className="w-full p-2 border rounded" value={profileForm.password} onChange={e => setProfileForm({ ...profileForm, password: e.target.value })} /></div>
                    <div className="flex gap-4 pt-4">
                        <button type="submit" className="bg-flame text-white px-4 py-2 rounded font-bold">Save Changes</button>
                        <button type="button" onClick={() => setEditingProfile(false)} className="bg-gray-300 px-4 py-2 rounded font-bold">Cancel</button>
                    </div>
                </form>
            ) : (
                <div className="bg-white p-6 rounded-lg border border-neutral-200 shadow-sm relative">
                    <button onClick={() => setEditingProfile(true)} className="absolute top-4 right-4 text-sm text-blue-600 underline">Edit</button>
                    <div className="flex flex-col md:flex-row gap-8 items-center md:items-start">
                        <div className="w-32 h-32 rounded-full overflow-hidden border-4 border-beige shadow-md bg-gray-100 flex-shrink-0 flex items-center justify-center">
                            {profile.profileImage ? (
                                <img src={profile.profileImage} alt="Profile" className="w-full h-full object-cover" />
                            ) : (
                                <span className="text-4xl">👤</span>
                            )}
                        </div>
                        <div className="grid grid-cols-1 gap-6 w-full">
                            <div><p className="text-xs text-gray-500 uppercase">Name</p><p className="font-medium text-lg">{profile.name}</p></div>
                            <div><p className="text-xs text-gray-500 uppercase">Email</p><p className="font-medium text-lg">{profile.email}</p></div>
                            <div><p className="text-xs text-gray-500 uppercase">Phone</p><p className="font-medium text-lg">{profile.phoneNumber || 'Not provided'}</p></div>
                            <div><p className="text-xs text-gray-500 uppercase">Member Since</p><p className="font-medium text-lg">{new Date(profile.createdAt).toLocaleDateString()}</p></div>
                        </div>
                    </div>
                </div>
            )}
        </div>
    );

    const renderAddresses = () => (
        <div className="space-y-6">
            <div className="flex justify-between items-center">
                <h2 className="text-2xl font-bold text-charcoal">Address Book</h2>
                <button onClick={() => setAddingAddress(!addingAddress)} className="text-sm bg-charcoal text-white px-3 py-1 rounded">
                    {addingAddress ? 'Cancel' : '+ Add New'}
                </button>
            </div>

            {addingAddress && (
                <form onSubmit={handleAddAddress} className="bg-beige p-6 rounded-lg space-y-4 mb-6 animate-fade-in">
                    <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                        <input placeholder="Street Address" required className="p-2 border rounded" value={addressForm.street} onChange={e => setAddressForm({ ...addressForm, street: e.target.value })} />
                        <input placeholder="City" required className="p-2 border rounded" value={addressForm.city} onChange={e => setAddressForm({ ...addressForm, city: e.target.value })} />
                        <input placeholder="Postal Code" required className="p-2 border rounded" value={addressForm.postalCode} onChange={e => setAddressForm({ ...addressForm, postalCode: e.target.value })} />
                        <input placeholder="Country" required className="p-2 border rounded" value={addressForm.country} onChange={e => setAddressForm({ ...addressForm, country: e.target.value })} />
                    </div>
                    <button type="submit" className="bg-flame text-white px-4 py-2 rounded font-bold shadow-md">Save Address</button>
                </form>
            )}

            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                {profile.addresses && profile.addresses.length > 0 ? (
                    profile.addresses.map((addr, idx) => (
                        <div key={idx} className="p-4 border border-neutral-200 rounded-lg relative hover:shadow-md transition bg-white">
                            <button onClick={() => handleRemoveAddress(idx)} className="absolute top-2 right-2 text-red-500 hover:text-red-700">✕</button>
                            <p className="font-bold">{addr.street}</p>
                            <p>{addr.city}, {addr.postalCode}</p>
                            <p className="text-sm text-gray-500 uppercase">{addr.country}</p>
                        </div>
                    ))
                ) : (
                    <p className="text-gray-500 italic">No addresses saved.</p>
                )}
            </div>
        </div>
    );

    const renderWallet = () => (
        <div className="space-y-6">
            <div className="flex justify-between items-center">
                <h2 className="text-2xl font-bold text-charcoal">Wallet & Payment Methods</h2>
                <button onClick={() => setAddingCard(!addingCard)} className="text-sm bg-charcoal text-white px-3 py-1 rounded">
                    {addingCard ? 'Cancel' : '+ Add Card'}
                </button>
            </div>

            {addingCard && (
                <form onSubmit={handleAddCard} className="bg-neutral-100 p-6 rounded-lg space-y-4 border border-neutral-300">
                    <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                        <input placeholder="Card Number" required minLength="16" maxLength="16" className="p-2 border rounded md:col-span-2" value={cardForm.number} onChange={e => setCardForm({ ...cardForm, number: e.target.value })} />
                        <input placeholder="Expiry (MM/YY)" required className="p-2 border rounded" value={cardForm.expiry} onChange={e => setCardForm({ ...cardForm, expiry: e.target.value })} />
                        <input placeholder="CVC" required className="p-2 border rounded" maxLength="4" value={cardForm.cvc} onChange={e => setCardForm({ ...cardForm, cvc: e.target.value })} />
                        <input placeholder="Card Holder Name" required className="p-2 border rounded md:col-span-2" value={cardForm.holderName} onChange={e => setCardForm({ ...cardForm, holderName: e.target.value })} />
                    </div>
                    <button type="submit" className="bg-blue-600 text-white px-4 py-2 rounded font-bold shadow-md w-full">Encrypt & Save Card</button>
                </form>
            )}

            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                {profile.paymentMethods && profile.paymentMethods.length > 0 ? (
                    profile.paymentMethods.map((method, idx) => (
                        <div key={idx} className="relative p-6 rounded-xl text-white shadow-xl bg-gradient-to-r from-gray-700 to-gray-900 h-48 flex flex-col justify-between transform hover:scale-105 transition-transform">
                            <button onClick={() => handleRemoveCard(idx)} className="absolute top-4 right-4 text-white/50 hover:text-white">✕</button>
                            <div className="flex justify-between items-start">
                                <span className="font-mono text-xs opacity-70">Credit Card</span>
                                <span className="font-bold tracking-wider">{method.cardType}</span>
                            </div>
                            <div className="text-2xl tracking-widest font-mono">
                                **** **** **** {method.last4}
                            </div>
                            <div className="flex justify-between items-end">
                                <div>
                                    <p className="text-[10px] uppercase opacity-70">Card Holder</p>
                                    <p className="font-medium tracking-wide">{method.holderName}</p>
                                </div>
                                <div>
                                    <p className="text-[10px] uppercase opacity-70">Expires</p>
                                    <p className="font-medium">{method.expiryDate}</p>
                                </div>
                            </div>
                        </div>
                    ))
                ) : (
                    <p className="text-gray-500 italic">No payment methods saved.</p>
                )}
            </div>
        </div>
    );

    // Default Order Component reuse (Simplified)
    // Helper to dynamically load Razorpay script
    const loadRazorpay = () => {
        return new Promise((resolve) => {
            if (window.Razorpay) {
                resolve(true);
                return;
            }
            const script = document.createElement('script');
            script.src = 'https://checkout.razorpay.com/v1/checkout.js';
            script.onload = () => {
                resolve(true);
            };
            script.onerror = () => {
                resolve(false);
            };
            document.body.appendChild(script);
        });
    };

    const handleRetryPayment = async (order) => {
        try {
            // 1. Load Razorpay Script
            const resScript = await loadRazorpay();
            if (!resScript) {
                throw new Error('Razorpay SDK failed to load. Check your internet connection.');
            }

            // 2. Create Razorpay Order (using existing backend order)
            const payRes = await fetch(`${API_BASE_URL}/api/orders/pay/${order._id}`, {
                method: 'POST',
                headers: { 'Authorization': `Bearer ${user.token}` }
            });

            let paymentData;
            try {
                paymentData = await payRes.json();
            } catch (error) {
                throw new Error(`Server Error: (${payRes.status})`);
            }

            if (!payRes.ok) throw new Error(paymentData.message || 'Failed to initiate payment');

            // 3. Open Razorpay
            const options = {
                key: import.meta.env.VITE_RAZORPAY_KEY_ID,
                amount: paymentData.amount,
                currency: "INR",
                name: "CandlesWithKinzee",
                description: `Retry Order #${order._id}`,
                order_id: paymentData.id,
                handler: async function (response) {
                    try {
                        const verifyRes = await fetch(`${API_BASE_URL}/api/orders/pay/verify`, {
                            method: 'POST',
                            headers: {
                                'Content-Type': 'application/json',
                                'Authorization': `Bearer ${user.token}`
                            },
                            body: JSON.stringify({
                                razorpay_order_id: response.razorpay_order_id,
                                razorpay_payment_id: response.razorpay_payment_id,
                                razorpay_signature: response.razorpay_signature,
                                order_id: order._id
                            })
                        });

                        if (!verifyRes.ok) throw new Error(`Verification Failed: ${verifyRes.status}`);
                        const ct = verifyRes.headers.get("content-type");
                        if (!ct || !ct.includes("application/json")) throw new TypeError("Non-JSON Verify response");

                        const verifyData = await verifyRes.json();
                        if (verifyRes.ok) {
                            addToast('Payment Successful!', 'success');
                            fetchOrders(); // Refresh order list
                        } else {
                            addToast(verifyData.message || 'Payment Verification Failed', 'error');
                        }
                    } catch (err) {
                        addToast('Verification Error: ' + err.message, 'error');
                    }
                },
                prefill: {
                    name: user.name,
                    email: user.email,
                },
                theme: {
                    color: "#D97706"
                }
            };

            const rzp1 = new window.Razorpay(options);
            rzp1.open();

        } catch (error) {
            console.error(error);
            addToast(error.message, 'error');
        }
    };

    const renderOrderHistory = () => (
        <div className="space-y-4">
            <h2 className="text-2xl font-bold text-charcoal">Recent Orders</h2>
            {orders.length === 0 ? <p>No orders found.</p> : orders.map(order => (
                <div key={order._id} className="p-4 border rounded hover:bg-gray-50 flex flex-col md:flex-row justify-between items-start md:items-center space-y-2 md:space-y-0">
                    <div>
                        <div className="flex items-center space-x-2">
                            <span className="font-bold">Order #{order._id.substring(order._id.length - 6)}</span>
                            <span className="text-xs text-gray-400">({new Date(order.createdAt).toLocaleDateString()})</span>
                        </div>
                        <p className="text-sm">Total: <span className="font-semibold">${order.totalPrice.toFixed(2)}</span></p>
                        <div className="flex space-x-2 mt-1 text-sm">
                            <span className={`px-2 py-0.5 rounded ${order.isPaid ? "bg-green-100 text-green-700" : "bg-red-100 text-red-700"}`}>
                                {order.isPaid ? "Paid" : "Unpaid"}
                            </span>
                            <span className={`px-2 py-0.5 rounded ${order.isDelivered ? "bg-green-100 text-green-700" : "bg-yellow-100 text-yellow-700"}`}>
                                {order.isDelivered ? "Delivered" : (order.status || "Processing")}
                            </span>
                        </div>
                    </div>
                    {!order.isPaid && (
                        <button
                            onClick={() => handleRetryPayment(order)}
                            className="bg-flame text-white px-4 py-2 rounded font-bold hover:bg-brown transition text-sm"
                        >
                            Pay Now
                        </button>
                    )}
                </div>
            ))}
        </div>
    );

    const renderContent = () => {
        switch (activeSection) {
            case 'profile': return renderProfileDetails();
            case 'addresses': return renderAddresses();
            case 'wallet': return renderWallet();
            case 'orders':
            default: return renderOrderHistory();
        }
    };

    // ... (rest of NavButton and renderContent logic remains similar, adapted below)

    const NavButton = ({ section, icon, label }) => (
        <button
            onClick={() => setActiveSection(section)}
            className={`flex items-center space-x-3 w-full p-3 rounded-lg font-medium transition duration-200 
                ${activeSection === section
                    ? 'text-flame bg-flame/10'
                    : 'text-charcoal/70 hover:text-brown hover:bg-brown/5'
                }`
            }
        >
            <span className="text-xl">{icon}</span>
            <span>{label}</span>
        </button>
    );

    return (
        <motion.div
            className="min-h-screen bg-beige p-4 md:p-12"
            variants={pageVariants}
            initial="initial"
            animate="animate"
        >
            <SEO title="My Account" description="Manage your CandlesWithKinzee profile." />
            <div className="container mx-auto">
                {/* ... Header ... */}
                <div className="flex items-center gap-4 mb-8 justify-center md:justify-start">
                    {user.profileImage ? (
                        <img src={user.profileImage} alt={user.name} className="w-16 h-16 rounded-full object-cover shadow-md border-2 border-white" />
                    ) : (
                        <span className="text-5xl">👤</span>
                    )}
                    <h1 className="text-4xl font-extrabold text-brown">
                        Welcome, {user.name}!
                    </h1>
                </div>
                <div className="flex flex-col lg:flex-row gap-8">
                    <div className="lg:w-1/4 h-fit border-b lg:border-b-0 lg:border-r border-brown/10 pb-6 lg:pb-0 lg:pr-6">
                        <nav className="space-y-2">
                            <NavButton
                                section="profile"
                                icon={user.profileImage ? <img src={user.profileImage} alt="Profile" className="w-6 h-6 rounded-full object-cover" /> : "👤"}
                                label="Profile Details"
                            />
                            <NavButton section="addresses" icon="🏠" label="Address Book" />
                            <NavButton section="wallet" icon="💳" label="Wallet" />
                            <NavButton section="orders" icon="📦" label="My Orders" />
                        </nav>
                    </div>
                    <motion.div
                        key={activeSection}
                        className="lg:w-3/4 pl-0 lg:pl-6"
                        initial={{ opacity: 0, x: 20 }}
                        animate={{ opacity: 1, x: 0 }}
                        transition={{ duration: 0.4 }}
                    >
                        {renderContent()}
                    </motion.div>
                </div>
            </div>
        </motion.div>
    );
};

export default ProfilePage;

import React, { useState, useEffect, useContext } from 'react';
import { motion } from 'framer-motion';
import SEO from '../components/SEO.jsx';
import AuthContext from '../context/AuthContext';
import { useToast } from '../context/ToastContext';
import API_BASE_URL from '../config/api';

// --- Icons ---
const DashboardIcon = () => <svg xmlns="http://www.w3.org/2000/svg" width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><rect x="3" y="3" width="7" height="7"></rect><rect x="14" y="3" width="7" height="7"></rect><rect x="14" y="14" width="7" height="7"></rect><rect x="3" y="14" width="7" height="7"></rect></svg>;
const ProductIcon = () => <svg xmlns="http://www.w3.org/2000/svg" width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="M6 2L3 6v14a2 2 0 0 0 2 2h14a2 2 0 0 0 2-2V6l-3-4z"></path><line x1="3" y1="6" x2="21" y2="6"></line><path d="M16 10a4 4 0 0 1-8 0"></path></svg>;
const OrderIcon = () => <svg xmlns="http://www.w3.org/2000/svg" width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="M6 2L3 6v14a2 2 0 0 0 2 2h14a2 2 0 0 0 2-2V6l-3-4z"></path><line x1="3" y1="6" x2="21" y2="6"></line><path d="M16 10a4 4 0 0 1-8 0"></path></svg>;
const UserIcon = () => <svg xmlns="http://www.w3.org/2000/svg" width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="M20 21v-2a4 4 0 0 0-4-4H8a4 4 0 0 0-4 4v2"></path><circle cx="12" cy="7" r="4"></circle></svg>;
const HistoryIcon = () => <svg xmlns="http://www.w3.org/2000/svg" width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><circle cx="12" cy="12" r="10"></circle><polyline points="12 6 12 12 16 14"></polyline></svg>;
const TrashIcon = () => <svg xmlns="http://www.w3.org/2000/svg" width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><polyline points="3 6 5 6 21 6"></polyline><path d="M19 6v14a2 2 0 0 1-2 2H7a2 2 0 0 1-2-2V6m3 0V4a2 2 0 0 1 2-2h4a2 2 0 0 1 2 2v2"></path></svg>;
const EditIcon = () => <svg xmlns="http://www.w3.org/2000/svg" width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="M11 4H4a2 2 0 0 0-2 2v14a2 2 0 0 0 2 2h14a2 2 0 0 0 2-2v-7"></path><path d="M18.5 2.5a2.121 2.121 0 0 1 3 3L12 15l-4 1 1-4 9.5-9.5z"></path></svg>;

import { Link } from 'react-router-dom';

const AdminDashboard = () => {
    const [activeSection, setActiveSection] = useState('dashboard');
    const { user } = useContext(AuthContext);
    const { addToast } = useToast();

    // Data State
    const [stats, setStats] = useState({ revenue: 0, ordersCount: 0, usersCount: 0, lowStock: 0 });
    const [products, setProducts] = useState([]);
    const [deletedProducts, setDeletedProducts] = useState([]); // History
    const [orders, setOrders] = useState([]);
    const [usersList, setUsersList] = useState([]);
    const [loading, setLoading] = useState(false);

    // Form State
    const [editingProduct, setEditingProduct] = useState(null); // For Edit Mode
    const [productForm, setProductForm] = useState({ name: '', price: '', countInStock: '', category: '', description: '', image: '' });

    // Categories
    const categories = ['Aromatherapy', 'Soy Wax', 'Pillar Candles', 'Scented Votives', 'Seasonal', 'Decorative'];

    useEffect(() => {
        if (activeSection === 'dashboard') fetchStats();
        if (activeSection === 'products') fetchProducts();
        if (activeSection === 'orders') fetchOrders();
        // if (activeSection === 'users') fetchUsers(); // User management not fully implemented yet
        if (activeSection === 'history') fetchDeletedProducts();
    }, [activeSection, user.token]);

    const fetchStats = async () => {
        try {
            const res = await fetch(`${API_BASE_URL}/api/admin/stats`, { headers: { Authorization: `Bearer ${user.token}` } });
            if (!res.ok) throw new Error(`API: ${res.status}`);
            const ct = res.headers.get("content-type");
            if (!ct || !ct.includes("application/json")) throw new TypeError("Non-JSON API response");
            const data = await res.json();
            setStats({
                revenue: data.totalRevenue || 0,
                ordersCount: data.totalOrders || 0,
                usersCount: data.totalUsers || 0,
                lowStock: data.lowStockProducts || 0
            });
        } catch (error) { console.error(error); }
    };

    const fetchProducts = async () => {
        try {
            const res = await fetch(`${API_BASE_URL}/api/products?showAll=true`);
            if (!res.ok) throw new Error(`API: ${res.status}`);
            const ct = res.headers.get("content-type");
            if (!ct || !ct.includes("application/json")) throw new TypeError("Non-JSON API response");
            const data = await res.json();
            setProducts(data);
        } catch (error) { console.error(error); }
    };

    const fetchDeletedProducts = async () => {
        try {
            const res = await fetch(`${API_BASE_URL}/api/products/history`, { headers: { Authorization: `Bearer ${user.token}` } });
            if (!res.ok && res.status !== 401) throw new Error(`API: ${res.status}`);
            if (res.status === 401) {
                addToast('Session expired. Please login again.', 'error');
                return;
            }
            const data = await res.json();
            if (Array.isArray(data)) {
                setDeletedProducts(data);
            } else {
                setDeletedProducts([]);
            }
        } catch (error) {
            console.error(error);
            setDeletedProducts([]);
        }
    };

    const fetchOrders = async () => {
        try {
            const res = await fetch(`${API_BASE_URL}/api/orders`, { headers: { Authorization: `Bearer ${user.token}` } });
            if (!res.ok) throw new Error(`API: ${res.status}`);
            const ct = res.headers.get("content-type");
            if (!ct || !ct.includes("application/json")) throw new TypeError("Non-JSON API response");
            const data = await res.json();
            setOrders(data);
        } catch (error) { console.error(error); }
    };

    const handleProductSubmit = async (e) => {
        e.preventDefault();
        setLoading(true);
        const url = editingProduct ? `${API_BASE_URL}/api/products/${editingProduct._id}` : `${API_BASE_URL}/api/products`;
        const method = editingProduct ? 'PUT' : 'POST';

        try {
            const res = await fetch(url, {
                method: method,
                headers: { 'Content-Type': 'application/json', Authorization: `Bearer ${user.token}` },
                body: JSON.stringify(productForm)
            });

            if (!res.ok && res.status !== 401) throw new Error(`API: ${res.status}`);

            if (res.status === 401) {
                addToast('Session expired. Please login again.', 'error');
                setLoading(false);
                return;
            }

            if (res.ok) {
                addToast(editingProduct ? 'Product Updated' : 'Product Created', 'success');
                setProductForm({ name: '', price: '', countInStock: '', category: '', description: '', image: '' });
                setEditingProduct(null);
                fetchProducts();
            } else {
                const data = await res.json();
                addToast(data.message || 'Operation failed', 'error');
            }
        } catch (error) {
            addToast(error.message, 'error');
        } finally {
            setLoading(false);
        }
    };

    const handleEditClick = (product) => {
        setEditingProduct(product);
        setProductForm({
            name: product.name,
            price: product.price,
            countInStock: product.countInStock,
            category: product.category,
            description: product.description,
            image: (product.image && typeof product.image === 'object')
                ? (product.image.secure_url || product.image.url || product.image.image)
                : (product.image || '')
        });
        window.scrollTo(0, 0); // Scroll to form
    };

    const handleDeleteProduct = async (id) => {
        if (!window.confirm('Are you sure? This will move the product to history.')) return;
        try {
            const res = await fetch(`${API_BASE_URL}/api/products/${id}`, {
                method: 'DELETE',
                headers: { Authorization: `Bearer ${user.token}` }
            });
            if (!res.ok) throw new Error(`Delete Failed: ${res.status}`);
            if (res.ok) {
                addToast('Product moved to history', 'success');
                fetchProducts();
                // Optionally refetch history if we were finding a way to update counts
            }
        } catch (error) { console.error(error); }
    };

    const handleStatusUpdate = async (id, status) => {
        if (!window.confirm(`Update order status to "${status}"?`)) return;
        try {
            const res = await fetch(`${API_BASE_URL}/api/orders/${id}/deliver`, {
                method: 'PUT',
                headers: {
                    'Content-Type': 'application/json',
                    Authorization: `Bearer ${user.token}`
                },
                body: JSON.stringify({ status })
            });

            if (!res.ok) throw new Error(`Update Failed: ${res.status}`);

            if (res.ok) {
                addToast(`Order updated to ${status}`, 'success');
                fetchOrders();
            } else {
                const data = await res.json();
                addToast(data.message || 'Operation failed', 'error');
            }
        } catch (error) { console.error(error); }
    };


    // --- Sub-components ---

    const StatsCard = ({ title, value, color, flicker }) => (
        <motion.div whileHover={{ scale: 1.05 }} className={`p-6 bg-white rounded-xl shadow-lg border-l-4 ${color}`}>
            <p className="text-charcoal/70 font-medium text-sm uppercase tracking-wider">{title}</p>
            <p className={`text-3xl font-bold text-charcoal mt-2 ${flicker ? 'animate-pulse' : ''}`}>{value}</p>
        </motion.div>
    );

    const DashboardHome = () => (
        <div className="space-y-8">
            <h2 className="text-3xl font-bold text-white mb-6">Dashboard Overview</h2>
            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
                <StatsCard title="Total Revenue" value={`$${stats.revenue.toFixed(2)}`} color="border-green-500" />
                <StatsCard title="Total Orders" value={stats.ordersCount} color="border-blue-500" />
                <StatsCard title="Total Users" value={stats.usersCount} color="border-purple-500" />
                <StatsCard title="Low Stock Alerts" value={stats.lowStock} color="border-red-500" flicker={stats.lowStock > 0} />
            </div>
        </div>
    );

    const renderProductSection = () => (
        <div className="space-y-6">
            <h2 className="text-3xl font-bold text-white">Product Management</h2>

            {/* Add/Edit Product Form */}
            <div className="bg-white p-6 rounded-xl shadow-lg">
                <h3 className="text-xl font-bold text-brown mb-4">{editingProduct ? `Edit Product: ${editingProduct.name}` : 'Add New Product'}</h3>
                <form onSubmit={handleProductSubmit} className="grid grid-cols-1 md:grid-cols-2 gap-4">
                    <input type="text" placeholder="Product Name" required className="p-3 border border-shadow rounded-lg" value={productForm.name} onChange={e => setProductForm({ ...productForm, name: e.target.value })} />

                    <input
                        type="text"
                        list="category-options"
                        placeholder="Category (Select or Type New)"
                        required
                        className="p-3 border border-shadow rounded-lg"
                        value={productForm.category}
                        onChange={e => setProductForm({ ...productForm, category: e.target.value })}
                    />
                    <datalist id="category-options">
                        {categories.map(c => <option key={c} value={c} />)}
                    </datalist>

                    <input type="number" placeholder="Price ($)" required className="p-3 border border-shadow rounded-lg" value={productForm.price} onChange={e => setProductForm({ ...productForm, price: e.target.value })} />
                    <input type="number" placeholder="Stock Quantity" required className="p-3 border border-shadow rounded-lg" value={productForm.countInStock} onChange={e => setProductForm({ ...productForm, countInStock: e.target.value })} />
                    {/* Image Upload Handlers */}
                    <div className="md:col-span-2 space-y-2">
                        <label className="block text-charcoal font-bold mb-1">Product Image</label>
                        <div className="flex flex-col md:flex-row gap-4">
                            <input
                                type="text"
                                placeholder="Enter Image URL"
                                className="flex-1 p-3 border border-shadow rounded-lg"
                                value={productForm.image}
                                onChange={e => setProductForm({ ...productForm, image: e.target.value })}
                            />
                            <div className="relative">
                                <input
                                    type="file"
                                    id="image-file"
                                    className="hidden"
                                    onChange={async (e) => {
                                        const file = e.target.files[0];
                                        if (!file) return;
                                        const formData = new FormData();
                                        formData.append('image', file);
                                        try {
                                            setLoading(true);
                                            const res = await fetch(`${API_BASE_URL}/api/upload`, {
                                                method: 'POST',
                                                body: formData,
                                            });
                                            if (!res.ok) throw new Error('Upload Failed');
                                            const data = await res.json();
                                            setProductForm({ ...productForm, image: data.url });
                                            setLoading(false);
                                        } catch (error) {
                                            console.error(error);
                                            setLoading(false);
                                        }
                                    }}
                                />
                                <label
                                    htmlFor="image-file"
                                    className="cursor-pointer bg-gray-200 text-charcoal px-4 py-3 rounded-lg hover:bg-gray-300 transition block text-center"
                                >
                                    Choose File
                                </label>
                            </div>
                        </div>
                        {productForm.image && (
                            <div className="mt-2 text-sm text-green-600">
                                Image Selected: {productForm.image}
                            </div>
                        )}
                    </div>
                    <textarea placeholder="Description" required className="p-3 border border-shadow rounded-lg md:col-span-2 h-24" value={productForm.description} onChange={e => setProductForm({ ...productForm, description: e.target.value })}></textarea>

                    <div className="md:col-span-2 flex gap-4">
                        <button type="submit" disabled={loading} className="flex-1 py-3 bg-flame text-white font-bold rounded-lg hover:bg-brown transition disabled:opacity-50">
                            {editingProduct ? 'Update Product' : 'Add Product'}
                        </button>
                        {editingProduct && (
                            <button type="button" onClick={() => { setEditingProduct(null); setProductForm({ name: '', price: '', countInStock: '', category: '', description: '', image: '' }); }} className="py-3 px-6 bg-gray-300 text-charcoal font-bold rounded-lg hover:bg-gray-400 transition">
                                Cancel
                            </button>
                        )}
                    </div>
                </form>
            </div>

            {/* Product Table */}
            <div className="bg-white p-6 rounded-xl shadow-lg overflow-x-auto">
                <h3 className="text-xl font-bold text-brown mb-4">Active Inventory</h3>
                <table className="w-full text-left border-collapse">
                    <thead>
                        <tr className="border-b border-shadow/30 text-charcoal/70 text-sm">
                            <th className="p-3">Name</th>
                            <th className="p-3">Category</th>
                            <th className="p-3">Price</th>
                            <th className="p-3">Stock</th>
                            <th className="p-3">Actions</th>
                        </tr>
                    </thead>
                    <tbody>
                        {products.map(product => {
                            const isLowStock = product.countInStock > 0 && product.countInStock <= 5;
                            const isOutOfStock = product.countInStock === 0;

                            return (
                                <tr key={product._id} className="border-b border-shadow/10 hover:bg-beige/30 transition">
                                    <td className="p-3 font-semibold text-charcoal">{product.name}</td>
                                    <td className="p-3 text-sm">{product.category}</td>
                                    <td className="p-3">${product.price.toFixed(2)}</td>
                                    <td className="p-3 font-bold">
                                        {isOutOfStock ? (
                                            <span className="text-red-600 uppercase text-xs tracking-wider">Out of Stock</span>
                                        ) : isLowStock ? (
                                            <span className="text-[#FF9F1C] flex items-center gap-1">
                                                {product.countInStock} <span className="text-[10px] uppercase font-bold border border-[#FF9F1C] px-1 rounded">Low</span>
                                            </span>
                                        ) : (
                                            <span className="text-green-600">{product.countInStock}</span>
                                        )}
                                    </td>
                                    <td className="p-3 flex space-x-2">
                                        <Link to={`/admin/product/${product._id}/edit`} className="text-blue-500 hover:text-blue-700" title="Edit"><EditIcon /></Link>
                                        <button onClick={() => handleDeleteProduct(product._id)} className="text-red-500 hover:text-red-700" title="Delete"><TrashIcon /></button>
                                    </td>
                                </tr>
                            );
                        })}
                    </tbody>
                </table>
            </div>
        </div>
    );

    const HistorySection = () => (
        <div className="space-y-6">
            <h2 className="text-3xl font-bold text-white">Product History (All Records)</h2>
            <div className="bg-white p-6 rounded-xl shadow-lg overflow-x-auto">
                <p className="mb-4 text-charcoal/70">Complete record of every product ever added to the inventory.</p>
                <table className="w-full text-left border-collapse">
                    <thead>
                        <tr className="border-b border-shadow/30 text-charcoal/70 text-sm">
                            <th className="p-3">Name</th>
                            <th className="p-3">Category</th>
                            <th className="p-3">Price</th>
                            <th className="p-3">Stock</th>
                            <th className="p-3">Status</th>
                        </tr>
                    </thead>
                    <tbody>
                        {deletedProducts.length === 0 ? (
                            <tr><td colSpan="5" className="p-4 text-center text-gray-500">No records found.</td></tr>
                        ) : (
                            deletedProducts.map(product => (
                                <tr key={product._id} className={`border-b border-shadow/10 transition ${product.isDeleted ? 'bg-red-50 hover:bg-red-100' : 'hover:bg-beige/30'}`}>
                                    <td className="p-3 font-semibold text-charcoal">{product.name}</td>
                                    <td className="p-3 text-sm">{product.category}</td>
                                    <td className="p-3">${product.price.toFixed(2)}</td>
                                    <td className="p-3">{product.countInStock}</td>
                                    <td className="p-3">
                                        <span className={`px-2 py-1 rounded-full text-xs font-bold ${product.isDeleted ? 'bg-red-200 text-red-800' : 'bg-green-200 text-green-800'}`}>
                                            {product.isDeleted ? 'Deleted' : 'Active'}
                                        </span>
                                    </td>
                                </tr>
                            ))
                        )}
                    </tbody>
                </table>
            </div>
        </div>
    );

    const OrderSection = () => (
        <div className="space-y-6">
            <h2 className="text-3xl font-bold text-white">Orders</h2>
            {/* Placeholder for Orders implementation from previous steps - reusing basic structure */}
            <div className="bg-white p-6 rounded-xl shadow-lg overflow-x-auto">
                <table className="w-full text-left border-collapse">
                    <thead>
                        <tr className="border-b border-shadow/30 text-charcoal/70 text-sm">
                            <th className="p-3">Order ID</th>
                            <th className="p-3">User</th>
                            <th className="p-3">Date</th>
                            <th className="p-3">Total</th>
                            <th className="p-3">Paid</th>
                            <th className="p-3">Delivered</th>
                        </tr>
                    </thead>
                    <tbody>
                        {orders.map(order => (
                            <tr key={order._id} className="border-b border-shadow/10 hover:bg-beige/30 transition">
                                <td className="p-3 text-sm font-mono text-charcoal/70">{order._id}</td>
                                <td className="p-3 font-semibold text-charcoal">{order.user ? order.user.name : 'Unknown User'}</td>
                                <td className="p-3 text-sm">{order.createdAt.substring(0, 10)}</td>
                                <td className="p-3 text-flame font-bold">${order.totalPrice.toFixed(2)}</td>
                                <td className="p-3">
                                    {order.isPaid ? (
                                        <span className="text-green-600 bg-green-100 px-2 py-1 rounded text-xs font-bold">Paid</span>
                                    ) : (
                                        <span className="text-red-600 bg-red-100 px-2 py-1 rounded text-xs font-bold">Unpaid</span>
                                    )}
                                </td>
                                <td className="p-3">
                                    <div className="flex flex-col space-y-1">
                                        {/* Status Display */}
                                        <div className="mb-1 text-xs font-bold">
                                            {order.isDelivered ? (
                                                <span className="text-green-600">DELIVERED</span>
                                            ) : (order.status === 'Out for Delivery') ? (
                                                <span className="text-orange-500">OUT FOR DELIVERY</span>
                                            ) : (
                                                <span className="text-red-500">PENDING</span>
                                            )}
                                        </div>

                                        {/* Actions */}
                                        {!order.isDelivered && (
                                            <div className="flex space-x-2 text-[10px]">
                                                {/* Only show 'Out for Delivery' if not already there */}
                                                {order.status !== 'Out for Delivery' && (
                                                    <button
                                                        onClick={() => handleStatusUpdate(order._id, 'Out for Delivery')}
                                                        className="bg-yellow-100 text-yellow-800 px-2 py-1 rounded hover:bg-yellow-200"
                                                    >
                                                        Mark Out
                                                    </button>
                                                )}
                                                <button
                                                    onClick={() => handleStatusUpdate(order._id, 'Delivered')}
                                                    className="bg-green-100 text-green-800 px-2 py-1 rounded hover:bg-green-200"
                                                >
                                                    Mark Delivered
                                                </button>
                                            </div>
                                        )}
                                    </div>
                                </td>
                            </tr>
                        ))}
                    </tbody>
                </table>
            </div>
        </div>
    );

    const renderContent = () => {
        switch (activeSection) {
            case 'products': return renderProductSection();
            case 'orders': return <OrderSection />;
            case 'history': return <HistorySection />;
            default: return <DashboardHome />;
        }
    };

    return (
        <div className="min-h-screen bg-charcoal flex flex-col md:flex-row font-sans">
            <SEO title="Admin Dashboard" description="Admin dashboard" robots="noindex" />

            <nav className="w-full md:w-64 bg-brown/90 text-white p-6 flex-shrink-0">
                <h1 className="text-2xl font-serif font-bold mb-8 tracking-wider text-primary">AdminPanel</h1>
                <ul className="space-y-2">
                    {[
                        { id: 'dashboard', label: 'Dashboard', icon: DashboardIcon },
                        { id: 'products', label: 'Products', icon: ProductIcon },
                        { id: 'orders', label: 'Orders', icon: OrderIcon },
                        // Replaced Users with History for this specific task focus
                        { id: 'history', label: 'History', icon: HistoryIcon },
                    ].map(item => (
                        <li key={item.id}>
                            <button onClick={() => setActiveSection(item.id)} className={`flex items-center space-x-3 w-full p-3 rounded-lg transition duration-200 ${activeSection === item.id ? 'bg-flame text-white shadow-lg' : 'hover:bg-white/10'}`}>
                                <item.icon /> <span>{item.label}</span>
                            </button>
                        </li>
                    ))}
                </ul>
            </nav>

            <main className="flex-grow p-6 md:p-10 overflow-y-auto">
                <motion.div key={activeSection} initial={{ opacity: 0, y: 10 }} animate={{ opacity: 1, y: 0 }} transition={{ duration: 0.3 }}>
                    {renderContent()}
                </motion.div>
            </main>
        </div>
    );
};

export default AdminDashboard;

// src/CartPage.jsx

import React from 'react';
import { Link } from 'react-router-dom';
import { motion } from 'framer-motion';
import SEO from '../components/SEO.jsx';
import { useCart } from '../context/CartContext';
import { getValidImageUrl } from '../utils/imageHelper';

// Minimalist Cart Item
const CartItem = ({ item, onRemove, onUpdateQuantity }) => {
    return (
        <motion.div
            className="flex flex-col sm:flex-row items-center gap-6 py-8 border-b border-neutral-100 last:border-0"
            initial={{ opacity: 0 }}
            animate={{ opacity: 1 }}
            exit={{ opacity: 0 }}
        >
            <div className="w-full sm:w-24 h-32 bg-neutral-100 shrink-0">
                <img
                    src={getValidImageUrl(item.image)}
                    alt={item.name}
                    className="w-full h-full object-cover"
                    onError={(e) => { e.target.onerror = null; e.target.src = "https://placehold.co/100x120/E5E5E5/A3A3A3?text=Candle" }}
                />
            </div>

            <div className="flex-1 w-full text-center sm:text-left">
                <div className="flex flex-col sm:flex-row justify-between items-start">
                    <div>
                        <h3 className="font-serif text-xl text-charcoal mb-1">{item.name}</h3>
                        {/* Assuming brand/scent is part of product, or just generic subtitle */}
                        <p className="text-sm text-brown/60 mb-4">{item.brand || 'Luxury Collection'}</p>
                    </div>
                    <p className="text-lg font-medium text-charcoal hidden sm:block">${(item.price * item.quantity).toFixed(2)}</p>
                </div>

                <div className="flex items-center justify-center sm:justify-start gap-6">
                    <div className="flex items-center border border-neutral-300">
                        <button
                            className="px-3 py-1 text-charcoal hover:bg-neutral-100 transition"
                            onClick={() => onUpdateQuantity(item._id, Math.max(1, item.quantity - 1))}
                        >-</button>
                        <span className="px-3 py-1 text-sm font-medium w-8 text-center">{item.quantity}</span>
                        <button
                            className="px-3 py-1 text-charcoal hover:bg-neutral-100 transition disabled:opacity-30 disabled:cursor-not-allowed"
                            onClick={() => onUpdateQuantity(item._id, item.quantity + 1)}
                            disabled={item.quantity >= item.countInStock}
                        >+</button>
                    </div>

                    <button
                        onClick={() => onRemove(item._id)}
                        className="text-xs text-brown/50 uppercase tracking-wider hover:text-red-500 transition-colors border-b border-transparent hover:border-red-500 pb-0.5"
                    >
                        Remove
                    </button>
                </div>
            </div>
        </motion.div>
    );
};


const CartPage = () => {
    const { cartItems, removeFromCart, updateQuantity, cartTotal } = useCart();

    const subtotal = cartTotal;
    const shipping = subtotal > 50 ? 0 : 5.00;
    const total = subtotal + shipping;

    const pageVariants = {
        initial: { opacity: 0 },
        animate: { opacity: 1, transition: { duration: 0.5 } }
    };

    return (
        <motion.div
            className="min-h-screen bg-white"
            variants={pageVariants}
            initial="initial"
            animate="animate"
        >
            <SEO title="Shopping Cart" description="Review your selected items." />

            <div className="container mx-auto px-4 py-16 md:py-24">
                <h1 className="text-4xl md:text-5xl font-serif text-center text-charcoal mb-16">
                    Shopping Cart
                </h1>

                <div className="flex flex-col lg:flex-row gap-16 max-w-6xl mx-auto">

                    {/* 1. Item List Area */}
                    <div className="lg:w-2/3">
                        {cartItems.length > 0 ? (
                            <div className="border-t border-neutral-200">
                                {cartItems.map(item => (
                                    <CartItem
                                        key={item._id}
                                        item={item}
                                        onRemove={removeFromCart}
                                        onUpdateQuantity={updateQuantity}
                                    />
                                ))}
                            </div>
                        ) : (
                            <div className="text-center py-24 border border-dashed border-neutral-300 bg-neutral-50">
                                <p className="text-xl font-serif text-charcoal mb-4">Your cart is empty.</p>
                                <Link to="/shop" className="text-sm font-bold uppercase tracking-widest border-b-2 border-charcoal pb-1 hover:text-primary hover:border-primary transition-colors">
                                    Continue Shopping
                                </Link>
                            </div>
                        )}
                    </div>

                    {/* 2. Cart Summary (Clean Sticky) */}
                    <div className="lg:w-1/3">
                        <div className="bg-beige/30 p-8 sticky top-32">
                            <h2 className="font-serif text-2xl text-charcoal mb-8">Order Summary</h2>

                            <div className="space-y-4 mb-8 text-sm text-charcoal">
                                <div className="flex justify-between">
                                    <span className="text-brown/70">Subtotal</span>
                                    <span>${subtotal.toFixed(2)}</span>
                                </div>
                                <div className="flex justify-between">
                                    <span className="text-brown/70">Shipping</span>
                                    <span>{shipping === 0 || cartItems.length === 0 ? 'Free' : `$${shipping.toFixed(2)}`}</span>
                                </div>
                                <div className="pt-4 border-t border-brown/10 flex justify-between items-end">
                                    <span className="font-bold uppercase tracking-wide">Total</span>
                                    <span className="text-2xl font-serif">${(cartItems.length === 0 ? 0 : total).toFixed(2)}</span>
                                </div>
                            </div>

                            <Link to="/checkout" className="block w-full">
                                <button
                                    disabled={cartItems.length === 0}
                                    className="w-full py-4 bg-charcoal text-white font-bold uppercase tracking-widest text-xs hover:bg-black transition-all disabled:opacity-50 disabled:cursor-not-allowed"
                                >
                                    Proceed to Checkout
                                </button>
                            </Link>

                            <div className="mt-6 flex justify-center gap-4 opacity-50 grayscale hover:grayscale-0 transition-all duration-500">
                                {/* Payment Icons Placeholders */}
                                <div className="w-8 h-5 bg-neutral-300 rounded"></div>
                                <div className="w-8 h-5 bg-neutral-300 rounded"></div>
                                <div className="w-8 h-5 bg-neutral-300 rounded"></div>
                            </div>
                        </div>
                    </div>
                </div>
            </div>
        </motion.div>
    );
};

export default CartPage;

// src/CheckoutPage.jsx

import React, { useState } from 'react';
import { motion } from 'framer-motion';

import { Link, useNavigate } from 'react-router-dom';
import SEO from '../components/SEO.jsx';
import { useCart } from '../context/CartContext';
import AuthContext from '../context/AuthContext';
import { useToast } from '../context/ToastContext';
import API_BASE_URL from '../config/api';
import { getValidImageUrl } from '../utils/imageHelper';

// Placeholder Icons
const LockIcon = () => '🔒'; // For security
const LocationIcon = () => '📍'; // For shipping/location
const PaymentIcon = () => '💳'; // For payment

const CheckoutPage = () => {
    // Simple state to simulate checkout steps
    const [currentStep, setCurrentStep] = useState(1);
    const { cartItems, cartTotal, clearCart } = useCart();
    const { user } = React.useContext(AuthContext);
    const { addToast } = useToast();
    const navigate = useNavigate();

    const [shippingAddress, setShippingAddress] = useState({
        address: '',
        city: '',
        postalCode: '',
        country: ''
    });

    // Sync variables from user profile when available
    React.useEffect(() => {
        if (user && user.addresses && user.addresses.length > 0) {
            setShippingAddress(prev => ({
                ...prev,
                address: prev.address || user.addresses[0].street || '',
                city: prev.city || user.addresses[0].city || '',
                postalCode: prev.postalCode || user.addresses[0].postalCode || '',
                country: prev.country || user.addresses[0].country || ''
            }));
        }
    }, [user]);

    const subtotal = cartTotal;
    const shipping = 50.00;
    const taxes = 0;
    const total = subtotal + shipping + taxes;

    const handleAddressChange = (e) => {
        setShippingAddress({ ...shippingAddress, [e.target.name]: e.target.value });
    };

    // Helper to dynamically load Razorpay script
    const loadRazorpay = () => {
        return new Promise((resolve) => {
            if (window.Razorpay) {
                resolve(true);
                return;
            }
            const script = document.createElement('script');
            script.src = 'https://checkout.razorpay.com/v1/checkout.js';
            script.onload = () => {
                resolve(true);
            };
            script.onerror = () => {
                resolve(false);
            };
            document.body.appendChild(script);
        });
    };

    const handlePlaceOrder = async () => {
        if (!user) {
            addToast('Please login to place an order', 'error');
            navigate('/login');
            return;
        }

        try {
            // OPTIONAL: Update User Profile with new address if desired
            // The user requested to save the address to profile
            try {
                await fetch(`${API_BASE_URL}/api/auth/profile`, {
                    method: 'PUT',
                    headers: {
                        'Content-Type': 'application/json',
                        'Authorization': `Bearer ${user.token}`
                    },
                    body: JSON.stringify({
                        addresses: [{
                            street: shippingAddress.address,
                            city: shippingAddress.city,
                            postalCode: shippingAddress.postalCode,
                            country: shippingAddress.country
                        }]
                    })
                });
            } catch (profileErr) {
                console.warn("Failed to auto-save address to profile", profileErr);
            }

            // 1. Create Order
            const orderRes = await fetch(`${API_BASE_URL}/api/orders`, {
                method: 'POST',
                headers: {
                    'Content-Type': 'application/json',
                    'Authorization': `Bearer ${user.token}`
                },
                body: JSON.stringify({
                    orderItems: cartItems.map((item) => ({
                        product: item._id,
                        name: item.name,
                        image: getValidImageUrl(item.image),
                        price: item.price,
                        quantity: item.quantity,
                    })),
                    shippingAddress,
                    paymentMethod: 'Razorpay',
                    itemsPrice: subtotal,
                    taxPrice: taxes,
                    shippingPrice: shipping,
                    totalPrice: total
                })
            });

            // Robust JSON parsing
            if (!orderRes.ok) throw new Error(`Order Creation Failed: ${orderRes.status}`);
            const ct = orderRes.headers.get("content-type");
            if (!ct || !ct.includes("application/json")) throw new TypeError("Non-JSON Order response");

            let order;
            try {
                order = await orderRes.json();
            } catch (jsonErr) {
                const text = await orderRes.text();
                throw new Error(`Server Error: ${orderRes.statusText} (${orderRes.status})`);
            }

            if (!orderRes.ok) throw new Error(order.message || 'Failed to create order');

            // 2. Load Razorpay Script
            const res = await loadRazorpay();
            if (!res) {
                throw new Error('Razorpay SDK failed to load. Check your internet connection.');
            }

            // 3. Create Razorpay Order
            const payRes = await fetch(`${API_BASE_URL}/api/orders/pay/${order._id}`, {
                method: 'POST',
                headers: {
                    'Authorization': `Bearer ${user.token}`
                }
            });

            let paymentData;
            try {
                paymentData = await payRes.json();
            } catch (jsonErr) {
                throw new Error(`Payment Initiation Failed: Server Error (${payRes.status})`);
            }

            if (!payRes.ok) throw new Error(paymentData.message || 'Failed to initiate payment');

            // 4. Open Razorpay
            const options = {
                key: import.meta.env.VITE_RAZORPAY_KEY_ID,
                amount: paymentData.amount,
                currency: "INR",
                name: "CandlesWithKinzee",
                description: `Order #${order._id}`,
                order_id: paymentData.id,
                handler: async function (response) {
                    try {
                        const verifyRes = await fetch(`${API_BASE_URL}/api/orders/pay/verify`, {
                            method: 'POST',
                            headers: {
                                'Content-Type': 'application/json',
                                'Authorization': `Bearer ${user.token}`
                            },
                            body: JSON.stringify({
                                razorpay_order_id: response.razorpay_order_id,
                                razorpay_payment_id: response.razorpay_payment_id,
                                razorpay_signature: response.razorpay_signature,
                                order_id: order._id
                            })
                        });
                        const verifyData = await verifyRes.json();
                        if (verifyRes.ok) {
                            addToast('Payment Successful! Order Placed.', 'success');
                            clearCart();
                            navigate('/profile');
                        } else {
                            addToast(verifyData.message || 'Payment Verification Failed', 'error');
                        }
                    } catch (err) {
                        addToast('Verification Error: ' + err.message, 'error');
                    }
                },
                prefill: {
                    name: user.name,
                    email: user.email,
                },
                theme: {
                    color: "#D97706"
                }
            };

            const rzp1 = new window.Razorpay(options);
            rzp1.open();

        } catch (error) {
            console.error(error);
            addToast(error.message, 'error');
        }
    };

    // Framer Motion variant for page entry
    const pageVariants = {
        initial: { opacity: 0, y: 10 },
        animate: { opacity: 1, y: 0, transition: { duration: 0.5, ease: "easeOut" } }
    };

    const StepIndicator = ({ step, label }) => (
        <div className={`flex flex-col items-center w-1/3 ${step <= currentStep ? 'text-flame' : 'text-shadow'}`}>
            <div className={`w-8 h-8 rounded-full flex items-center justify-center font-bold mb-1 ${step <= currentStep ? 'bg-flame text-white' : 'bg-beige border border-shadow'}`}>
                {step}
            </div>
            <span className="text-sm font-medium hidden sm:block">{label}</span>
        </div>
    );

    const ShippingForm = () => (
        <motion.div initial={{ x: 50, opacity: 0 }} animate={{ x: 0, opacity: 1 }} transition={{ duration: 0.3 }} className="space-y-4">
            <h2 className="text-2xl font-bold text-brown flex items-center space-x-2">{LocationIcon()} <span>Shipping Address</span></h2>
            [cite_start]<p className="text-charcoal/70 text-sm">Location tracking helps with shipping estimation and address autofill[cite: 13].</p>

            {/* Saved Addresses Selection */}
            {user?.addresses?.length > 0 && (
                <div className="grid grid-cols-1 gap-2 mb-4">
                    <p className="text-sm font-bold text-charcoal">Saved Addresses:</p>
                    {user.addresses.map((addr, idx) => (
                        <button
                            key={idx}
                            type="button"
                            onClick={() => setShippingAddress({
                                address: addr.street,
                                city: addr.city,
                                postalCode: addr.postalCode,
                                country: addr.country
                            })}
                            className="text-left p-3 border border-shadow/50 rounded-lg hover:bg-beige transition text-xs flex justify-between items-center bg-white"
                        >
                            <span>{addr.street}, {addr.city}</span>
                            <span className="text-flame font-bold">Use</span>
                        </button>
                    ))}
                </div>
            )}

            <input type="text" placeholder="Full Name" className="w-full p-3 border border-shadow rounded-lg focus:ring-primary focus:border-primary" />
            <input name="address" value={shippingAddress.address} onChange={handleAddressChange} type="text" placeholder="Address Line 1" className="w-full p-3 border border-shadow rounded-lg focus:ring-primary focus:border-primary" required />
            <input name="city" value={shippingAddress.city} onChange={handleAddressChange} type="text" placeholder="City" className="w-full p-3 border border-shadow rounded-lg focus:ring-primary focus:border-primary" required />
            <div className="flex space-x-4">
                <input name="postalCode" value={shippingAddress.postalCode} onChange={handleAddressChange} type="text" placeholder="Zip/Postal Code" className="w-1/2 p-3 border border-shadow rounded-lg focus:ring-primary focus:border-primary" required />
                <input name="country" value={shippingAddress.country} onChange={handleAddressChange} type="text" placeholder="Country" className="w-1/2 p-3 border border-shadow rounded-lg focus:ring-primary focus:border-primary" required />
            </div>

            <motion.button
                type="button"
                className="w-full py-3 bg-primary text-charcoal font-bold rounded-lg hover:bg-flame hover:text-white transition"
                onClick={() => setCurrentStep(2)}
                whileHover={{ scale: 1.01 }}
                whileTap={{ scale: 0.99 }}
            >
                Continue to Payment
            </motion.button>
        </motion.div>
    );

    const PaymentForm = () => (
        <motion.div initial={{ x: 50, opacity: 0 }} animate={{ x: 0, opacity: 1 }} transition={{ duration: 0.3 }} className="space-y-4">
            <h2 className="text-2xl font-bold text-brown flex items-center space-x-2">{PaymentIcon()} <span>Payment Method</span></h2>
            [cite_start]<p className="text-charcoal/70 text-sm">Secure online transactions with payment gateway integration (Razorpay / Stripe)[cite: 9, 14, 18].</p>

            {/* Simulated Payment Gateway Form */}
            <div className="p-6 bg-beige rounded-lg border border-shadow space-y-4">
                <p className="text-sm text-charcoal flex items-center">
                    [cite_start]{LockIcon()} **Security is key.** You will be redirected to Razorpay's secure payment gateway to complete your purchase.[cite: 37].
                </p>
                <div className="flex items-center space-x-3 p-3 bg-white rounded border border-shadow/30">
                    <span className="font-bold text-lg text-blue-800">Razorpay</span>
                    <span className="text-sm text-gray-500">Secure Payment</span>
                </div>
            </div>

            <div className="flex space-x-4">
                <button
                    type="button"
                    className="w-1/3 py-3 border border-brown text-brown font-bold rounded-lg hover:bg-beige transition"
                    onClick={() => setCurrentStep(1)}
                >
                    &larr; Back to Shipping
                </button>
                <motion.button
                    type="button"
                    className="w-2/3 py-3 bg-flame text-white font-bold rounded-lg hover:bg-brown transition"
                    onClick={() => setCurrentStep(3)}
                    whileHover={{ scale: 1.01 }}
                    whileTap={{ scale: 0.99 }}
                >
                    Review Order
                </motion.button>
            </div>
        </motion.div>
    );

    const ReviewOrder = () => (
        <motion.div initial={{ x: 50, opacity: 0 }} animate={{ x: 0, opacity: 1 }} transition={{ duration: 0.3 }} className="space-y-6">
            <h2 className="text-2xl font-bold text-brown">Review & Place Order</h2>
            [cite_start]<p className="text-charcoal/70 text-sm">Final check before placing your order. Security is Flipkart-like secure checkout and encryption for user data[cite: 13].</p>

            {/* Review Sections */}
            <div className="grid md:grid-cols-2 gap-6">
                <div className="p-4 bg-beige rounded-lg border border-shadow/50">
                    <h3 className="font-semibold text-brown mb-2">Shipping Details</h3>
                    <p className="text-sm text-charcoal">{user?.name}</p>
                    <p className="text-sm text-charcoal">{shippingAddress.address}, {shippingAddress.city}, {shippingAddress.postalCode}, {shippingAddress.country}</p>
                    <button className="text-flame text-xs mt-1 hover:underline" onClick={() => setCurrentStep(1)}>Edit</button>
                </div>
                <div className="p-4 bg-beige rounded-lg border border-shadow/50">
                    <h3 className="font-semibold text-brown mb-2">Payment Details</h3>
                    <p className="text-sm text-charcoal">Method: Razorpay Secure</p>
                    <button className="text-flame text-xs mt-1 hover:underline" onClick={() => setCurrentStep(2)}>Edit</button>
                </div>
            </div>

            {/* Final Place Order Button */}
            <motion.button
                className="w-full py-4 bg-flame text-white font-extrabold text-xl rounded-lg shadow-xl hover:bg-brown transition"
                whileHover={{ scale: 1.02 }}
                whileTap={{ scale: 0.98 }}
                onClick={handlePlaceOrder}
            >
                Place Order (${total.toFixed(2)})
            </motion.button>

        </motion.div>
    );


    const renderFormContent = () => {
        switch (currentStep) {
            case 1: return <ShippingForm />;
            case 2: return <PaymentForm />;
            case 3: return <ReviewOrder />;
            default: return <ShippingForm />;
        }
    };


    return (
        <motion.div
            className="min-h-screen bg-beige p-4 md:p-12"
            variants={pageVariants}
            initial="initial"
            animate="animate"
        >
            <SEO title="Secure Checkout" description="Complete your purchase securely." robots="noindex, nofollow" />
            <div className="container mx-auto">
                <Link to="/cart" className="flex items-center text-brown hover:text-flame mb-4 text-sm font-medium transition">
                    &larr; Back to Cart
                </Link>

                <h1 className="text-4xl font-extrabold text-brown mb-8 text-center md:text-left flex items-center space-x-3">
                    {LockIcon()} <span>Secure Checkout</span>
                </h1>

                <div className="flex flex-col lg:flex-row gap-8">

                    {/* 1. Main Form Area */}
                    <div className="lg:w-3/5 p-2 md:p-0">

                        {/* Step Indicator */}
                        <div className="flex justify-between mb-12 pb-4 border-b border-brown/10">
                            <StepIndicator step={1} label="Shipping" />
                            <StepIndicator step={2} label="Payment" />
                            <StepIndicator step={3} label="Review" />
                        </div>

                        {/* Form Content (Animated) */}
                        <div key={currentStep}>
                            {renderFormContent()}
                        </div>
                    </div>

                    {/* 2. Order Summary Sidebar */}
                    <div className="lg:w-2/5 h-fit">
                        <div className="bg-white/50 backdrop-blur-sm p-8 rounded-2xl border border-white/50 sticky top-24">
                            <h2 className="text-2xl font-bold text-brown mb-6">Order Summary</h2>

                            <div className="space-y-4 text-charcoal">
                                <div className="flex justify-between">
                                    <span className="text-md opacity-80">Subtotal</span>
                                    <span className="font-semibold">${subtotal.toFixed(2)}</span>
                                </div>
                                <div className="flex justify-between">
                                    <span className="text-md opacity-80">Shipping</span>
                                    <span className="font-semibold text-primary">${shipping.toFixed(2)}</span>
                                </div>
                                <div className="flex justify-between border-b border-brown/10 pb-4">
                                    <span className="text-md opacity-80">Taxes (8%)</span>
                                    <span className="font-semibold">${taxes.toFixed(2)}</span>
                                </div>

                                <div className="flex justify-between pt-2">
                                    <span className="text-xl font-bold text-charcoal">Total</span>
                                    <span className="text-3xl font-serif text-flame">${total.toFixed(2)}</span>
                                </div>
                            </div>
                        </div>
                    </div>
                </div>
            </div>
        </motion.div>
    );
};

export default CheckoutPage;

// src/pages/HomePage.jsx

import React, { useState, useEffect, useRef } from 'react';
import { motion, useScroll, useTransform, useSpring } from 'framer-motion';
import { Link } from 'react-router-dom';
import SEO from '../components/SEO.jsx';
import ProductCard from '../components/ProductCard.jsx';
import heroImage from '../assets/hero.png';
import API_BASE_URL from '../config/api';

const HomePage = () => {
    const [featuredProducts, setFeaturedProducts] = useState([]);
    const containerRef = useRef(null);
    const { scrollY, scrollYProgress } = useScroll();

    // Luxuriously smooth spring for the progress bar
    const scaleX = useSpring(scrollYProgress, {
        stiffness: 70,
        damping: 25,
        mass: 0.5,
        restDelta: 0.001
    });

    // Parallax Effects
    const yHeroText = useTransform(scrollY, [0, 500], [0, 150]); // Text moves slower
    const yHeroImage = useTransform(scrollY, [0, 500], [0, -100]); // Image moves slightly up

    useEffect(() => {
        const fetchProducts = async () => {
            try {
                const res = await fetch(`${API_BASE_URL}/api/products`);
                if (!res.ok) throw new Error(`API Request Failed: ${res.status}`);

                const contentType = res.headers.get("content-type");
                if (!contentType || !contentType.includes("application/json")) {
                    throw new TypeError("Received HTML instead of JSON. Check API URL.");
                }

                const data = await res.json();
                setFeaturedProducts(data.slice(0, 4));
            } catch (error) {
                console.error('Error fetching products:', error);
            }
        };
        fetchProducts();
    }, []);

    // --- Animations ---
    const containerVariants = {
        hidden: { opacity: 0 },
        visible: {
            opacity: 1,
            transition: {
                staggerChildren: 0.15,
                delayChildren: 0.2
            }
        }
    };

    // Custom "Luxury" Bezier Curve
    const smoothEase = [0.25, 0.1, 0.25, 1]; // Similar to iOS ease-out

    const itemVariants = {
        hidden: { opacity: 0, y: 40 },
        visible: {
            opacity: 1,
            y: 0,
            transition: {
                duration: 1.2,
                ease: smoothEase
            }
        }
    };

    const bentoItems = [
        {
            title: "Aromatherapy",
            col: "md:col-span-2",
            row: "md:row-span-2",
            img: "https://placehold.co/800x800/F5C76B/2C2C2C?text=Aromatherapy",
            link: "/shop?category=aromatherapy"
        },
        {
            title: "Soy Wax",
            col: "md:col-span-1",
            row: "md:row-span-1",
            img: "https://placehold.co/600x600/FFF7E6/8B5E3C?text=Pure+Soy",
            link: "/shop?type=soy"
        },
        {
            title: "Gift Sets",
            col: "md:col-span-1",
            row: "md:row-span-2",
            img: "https://placehold.co/600x800/FF9F1C/FFFFFF?text=Gift+Sets",
            link: "/shop?category=gift"
        },
        {
            title: "Pillars",
            col: "md:col-span-1",
            row: "md:row-span-1",
            img: "https://placehold.co/600x600/8B5E3C/FFF7E6?text=Pillars",
            link: "/shop?type=pillar"
        },
    ];

    return (
        <motion.div
            className="bg-beige min-h-screen text-charcoal font-sans"
            initial="hidden"
            animate="visible"
            variants={containerVariants}
            ref={containerRef}
        >
            <SEO title="CandlesWithKinzee" description="Warm minimalist artisanal candles." />

            {/* Scroll Progress Bar */}
            <motion.div
                className="fixed top-0 left-0 right-0 h-1 bg-gradient-to-r from-primary to-flame origin-left z-[100]"
                style={{ scaleX }}
            />

            {/* 1. Hero Section: Refined Asymmetrical */}
            <section className="relative min-h-[90vh] flex items-center px-6 md:px-12 pt-32 pb-20 overflow-hidden">
                <div className="absolute inset-0 bg-gradient-to-b from-beige via-beige to-white/50 -z-20"></div>

                <div className="container mx-auto grid grid-cols-1 lg:grid-cols-2 gap-16 items-center">

                    {/* Text Content */}
                    <motion.div
                        style={{ y: yHeroText }}
                        variants={itemVariants}
                        className="z-10 order-2 lg:order-1 text-center lg:text-left flex flex-col justify-center"
                    >
                        <span className="block text-primary uppercase tracking-[0.4em] text-xs font-bold mb-8">
                            Handcrafted with Intention
                        </span>
                        <h1 className="text-5xl md:text-7xl lg:text-[5.5rem] font-serif leading-[1.1] mb-8 text-charcoal">
                            Light the <br />
                            <span className="italic font-light text-brown relative">
                                Moment.
                                {/* Decorative underline */}
                                <svg className="absolute w-full h-3 -bottom-2 left-0 text-primary/40 -z-10" viewBox="0 0 100 10" preserveAspectRatio="none">
                                    <path d="M0 5 Q 50 10 100 5" stroke="currentColor" strokeWidth="4" fill="transparent" />
                                </svg>
                            </span>
                        </h1>
                        <p className="text-lg text-charcoal/70 font-light mb-12 max-w-md mx-auto lg:mx-0 leading-relaxed">
                            Discover the art of slow living with our small-batch, sustainably sourced soy candles. Created to ground your space and elevate your everyday.
                        </p>
                        <Link to="/shop">
                            <motion.button
                                whileHover={{ scale: 1.02 }}
                                whileTap={{ scale: 0.98 }}
                                className="group inline-flex items-center gap-4 px-10 py-5 bg-charcoal text-beige font-medium shadow-xl hover:bg-brown transition-all duration-300"
                            >
                                <span className="uppercase tracking-widest text-xs font-bold">Shop Collection</span>
                                <span className="w-8 h-[1px] bg-beige group-hover:w-16 transition-all duration-500"></span>
                            </motion.button>
                        </Link>
                    </motion.div>

                    {/* Image Content */}
                    <div className="order-1 lg:order-2 relative flex justify-center items-center h-full min-h-[50vh]">
                        {/* Elegant Soft Backdrop Mask */}
                        <div className="absolute inset-0 bg-primary/5 rounded-[4rem] transform rotate-3 scale-105 -z-10"></div>
                        <div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 w-[140%] h-[140%] bg-white/60 blur-[100px] rounded-full -z-10" />

                        <motion.img
                            style={{ y: yHeroImage }}
                            src={heroImage}
                            alt="Floating Hero"
                            className="w-full max-w-sm md:max-w-md lg:max-w-xl object-contain drop-shadow-2xl z-10"
                            initial={{ opacity: 0, scale: 0.95, filter: "blur(10px)" }}
                            animate={{ opacity: 1, scale: 1, filter: "blur(0px)" }}
                            transition={{ duration: 1.8, ease: smoothEase }}
                        />
                    </div>
                </div>
            </section>

            {/* 2. Elevated Bento Grid Collection */}
            <section className="py-32 px-6 bg-white">
                <div className="container mx-auto max-w-7xl">
                    <motion.div
                        initial={{ opacity: 0, y: 30 }}
                        whileInView={{ opacity: 1, y: 0 }}
                        viewport={{ once: true, margin: "-10% 0px" }}
                        transition={{ duration: 1, ease: smoothEase }}
                        className="mb-16 text-center lg:text-left flex flex-col lg:flex-row justify-between items-end gap-6"
                    >
                        <div>
                            <span className="text-primary uppercase tracking-[0.2em] text-xs font-bold mb-4 block">The Collections</span>
                            <h2 className="text-4xl md:text-5xl font-serif text-charcoal">Curated Scents</h2>
                        </div>
                        <p className="text-charcoal/60 font-light max-w-sm text-sm leading-relaxed hidden lg:block pb-2">
                            Explore our bespoke categories, formulated to transform the atmosphere of every room.
                        </p>
                    </motion.div>

                    <div className="grid grid-cols-1 md:grid-cols-4 gap-4 h-auto md:h-[650px]">
                        {bentoItems.map((item, index) => (
                            <Link
                                to={item.link}
                                key={index}
                                className={`relative group overflow-hidden ${item.col} ${item.row} min-h-[300px] md:min-h-0 bg-neutral-100`}
                            >
                                {/* Background Image */}
                                <div className="absolute inset-0 overflow-hidden">
                                    <motion.img
                                        src={item.img}
                                        alt={item.title}
                                        className="w-full h-full object-cover transition-transform duration-[2s] ease-out group-hover:scale-110"
                                    />
                                    {/* Gradient overlay for text readability */}
                                    <div className="absolute inset-0 bg-gradient-to-t from-black/80 via-black/20 to-transparent opacity-70 group-hover:opacity-90 transition-opacity duration-700" />
                                </div>

                                {/* Content Overlay */}
                                <div className="absolute inset-x-0 bottom-0 p-8 z-10 flex flex-col justify-end h-full">
                                    <h3 className="text-3xl font-serif text-white tracking-wide mb-3 transform translate-y-4 group-hover:translate-y-0 transition-transform duration-700 ease-[0.25,0.1,0.25,1]">
                                        {item.title}
                                    </h3>
                                    <div className="flex items-center gap-3 text-white/90 opacity-0 group-hover:opacity-100 transform translate-y-4 group-hover:translate-y-0 transition-all duration-700 delay-[50ms] ease-[0.25,0.1,0.25,1]">
                                        <span className="text-xs font-medium uppercase tracking-[0.2em]">Explore</span>
                                        <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.5" strokeLinecap="round" strokeLinejoin="round"><path d="M5 12h14M12 5l7 7-7 7" /></svg>
                                    </div>
                                </div>
                            </Link>
                        ))}
                    </div>
                </div>
            </section>

            {/* 3. Featured Products */}
            <section className="py-32 bg-beige text-charcoal">
                <div className="container mx-auto px-6 max-w-7xl">
                    <motion.div
                        initial={{ opacity: 0 }}
                        whileInView={{ opacity: 1 }}
                        viewport={{ once: true }}
                        transition={{ duration: 1 }}
                        className="flex flex-col md:flex-row justify-between items-end mb-20 gap-8"
                    >
                        <div>
                            <span className="text-brown uppercase tracking-[0.2em] text-xs font-bold mb-3 block">Weekly Picks</span>
                            <h2 className="text-4xl md:text-5xl font-serif text-charcoal">Trending Now</h2>
                        </div>
                        <Link
                            to="/shop"
                            className="group inline-flex items-center gap-3 text-sm font-bold uppercase tracking-widest hover:text-brown transition-colors"
                        >
                            <span>Discover All</span>
                            <span className="block w-6 h-[1px] bg-charcoal group-hover:w-10 group-hover:bg-brown transition-all duration-300"></span>
                        </Link>
                    </motion.div>

                    <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-x-8 gap-y-16">
                        {featuredProducts.length > 0 ? (
                            featuredProducts.map((product, i) => (
                                <motion.div
                                    key={product._id}
                                    initial={{ opacity: 0, y: 40 }}
                                    whileInView={{ opacity: 1, y: 0 }}
                                    viewport={{ once: true, margin: "-50px" }}
                                    transition={{ duration: 1, delay: i * 0.1, ease: smoothEase }}
                                >
                                    <ProductCard product={product} />
                                </motion.div>
                            ))
                        ) : (
                            // Elegant Loading Skeletons
                            [1, 2, 3, 4].map(n => (
                                <div key={n} className="animate-pulse space-y-6 flex flex-col items-center">
                                    <div className="bg-charcoal/5 aspect-[4/5] w-full"></div>
                                    <div className="space-y-3 w-full px-4 text-center flex flex-col items-center">
                                        <div className="h-4 bg-charcoal/10 w-3/4"></div>
                                        <div className="h-3 bg-charcoal/10 w-1/4"></div>
                                    </div>
                                </div>
                            ))
                        )}
                    </div>
                </div>
            </section>

            {/* 4. Elegant Newsletter */}
            <section className="py-40 px-6 bg-charcoal text-beige relative overflow-hidden">
                {/* Soft ambient light blurs */}
                <div className="absolute top-0 right-0 w-[40rem] h-[40rem] bg-primary/5 rounded-full blur-[100px] -translate-y-1/2 translate-x-1/3 pointer-events-none"></div>
                <div className="absolute bottom-0 left-0 w-[40rem] h-[40rem] bg-flame/5 rounded-full blur-[100px] translate-y-1/2 -translate-x-1/3 pointer-events-none"></div>

                <div className="container mx-auto relative z-10 flex flex-col items-center text-center">
                    <motion.div
                        initial={{ opacity: 0, y: 40 }}
                        whileInView={{ opacity: 1, y: 0 }}
                        viewport={{ once: true }}
                        transition={{ duration: 1.2, ease: smoothEase }}
                        className="max-w-2xl w-full"
                    >
                        <span className="text-primary uppercase tracking-[0.3em] text-xs font-bold mb-6 block">Stay Connected</span>
                        <h2 className="text-4xl md:text-6xl font-serif mb-8 text-white tracking-wide">Join the Inner Circle</h2>
                        <p className="text-white/50 mb-16 font-light text-lg leading-relaxed max-w-lg mx-auto">
                            Sign up for exclusive early access to drops, special discounts, and a daily dose of calm delivered straight to your inbox.
                        </p>

                        <div className="flex flex-col sm:flex-row w-full max-w-md mx-auto relative group">
                            <input
                                type="email"
                                placeholder="Enter your email address"
                                className="flex-1 px-4 py-4 bg-transparent border-b border-white/30 text-white placeholder-white/30 focus:outline-none focus:border-primary transition-colors text-base text-center sm:text-left"
                            />
                            <button className="sm:absolute sm:right-0 sm:bottom-0 sm:top-0 mt-8 sm:mt-0 font-bold uppercase tracking-[0.2em] text-xs text-primary hover:text-white transition-colors flex items-center justify-center sm:justify-start gap-2 pr-4">
                                Subscribe
                            </button>
                        </div>
                    </motion.div>
                </div>
            </section>
        </motion.div>
    );
};

